import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card, Button, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { Title, Text, Tag, Space, Spin, Popconfirm } from '@/components/common';
import { useAppDispatch } from '../../../store/hooks';
import { fpcService } from '../../../services/fpc/service';
import type { PlanVoucherDraftDto } from '../../../services/fpc/types';
import styles from './PlanVoucherList.module.css';

const MONTH_LABELS: Record<number, string> = {
  1: 'Tháng 1', 2: 'Tháng 2', 3: 'Tháng 3', 4: 'Tháng 4',
  5: 'Tháng 5', 6: 'Tháng 6', 7: 'Tháng 7', 8: 'Tháng 8',
  9: 'Tháng 9', 10: 'Tháng 10', 11: 'Tháng 11', 12: 'Tháng 12',
};

const formatMoney = (v: number) =>
  new Intl.NumberFormat('vi-VN').format(v);

const PlanVoucherList: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [items, setItems] = useState<PlanVoucherDraftDto[]>([]);
  const [loading, setLoading] = useState(false);

  const fetchList = useCallback(async () => {
    setLoading(true);
    try {
      const list = await fpcService.getPlanVoucherList({});
      setItems(list);
    } catch {
      dispatchAppToast(dispatch, { message: 'Không thể tải danh sách phiếu kế hoạch', type: 'error' });
    } finally {
      setLoading(false);
    }
  }, [dispatch]);

  useEffect(() => { fetchList(); }, [fetchList]);

  const handleDelete = async (id: string) => {
    try {
      await fpcService.deletePlanVoucher(id);
      dispatchAppToast(dispatch, { message: 'Đã xóa phiếu kế hoạch', type: 'success' });
      fetchList();
    } catch {
      dispatchAppToast(dispatch, { message: 'Lỗi khi xóa phiếu kế hoạch', type: 'error' });
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.header}>
        <Title level={4}>Danh sách phiếu kế hoạch</Title>
        <Button variant="primary" onClick={() => navigate('/tc/kh/ke-hoach/new')}>
          Tạo mới
        </Button>
      </div>

      <Card>
        {loading ? (
          <div className={styles.loading}><Spin /> <Text>Đang tải...</Text></div>
        ) : items.length === 0 ? (
          <div className={styles.empty}>
            <Text type="secondary">Chưa có phiếu kế hoạch nào</Text>
            <Button variant="primary" onClick={() => navigate('/tc/kh/ke-hoach/new')}>
              Tạo phiếu đầu tiên
            </Button>
          </div>
        ) : (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Số phiếu</th>
                <th>Ngày lập</th>
                <th>Kỳ kế hoạch</th>
                <th>Chi nhánh</th>
                <th>Tổng KH</th>
                <th>Trạng thái</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {items.map(item => (
                <tr key={item.id} onClick={() => navigate(`/tc/kh/ke-hoach/${item.id}`)} className={styles.row}>
                  <td><strong>{item.code}</strong></td>
                  <td>{new Date(item.voucherDate).toLocaleDateString('vi-VN')}</td>
                  <td>
                    <Tag>{MONTH_LABELS[item.planMonth] ?? `T${item.planMonth}`}/{item.planYear}</Tag>
                  </td>
                  <td>{item.branchCode || 'Tất cả'}</td>
                  <td className={styles.amount}>{formatMoney(item.totalPlanned)}</td>
                  <td>
                    <Tag color={item.status === 'Draft' ? 'blue' : 'green'}>
                      {item.status === 'Draft' ? 'Nháp' : 'Đã ghi'}
                    </Tag>
                  </td>
                  <td>
                    <Space>
                      <Button size="sm" onClick={(e) => { e.stopPropagation(); navigate(`/tc/kh/ke-hoach/${item.id}`); }}>
                        Sửa
                      </Button>
                      <Popconfirm title="Xóa phiếu kế hoạch này?" onConfirm={() => handleDelete(item.id)}>
                        <Button size="sm">Xóa</Button>
                      </Popconfirm>
                    </Space>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </Card>
    </div>
  );
};

export default PlanVoucherList;
